questions.reference_solution:
function deepClone(obj, hash = new WeakMap()) {
  // null 或 undefined
  if (obj === null || obj === undefined) return obj;

  // 原始类型
  if (typeof obj !== 'object') return obj;

  // 循环引用检查
  if (hash.has(obj)) return hash.get(obj);

  // Date
  if (obj instanceof Date) {
    const copy = new Date(obj);
    hash.set(obj, copy);
    return copy;
  }

  // RegExp
  if (obj instanceof RegExp) {
    const copy = new RegExp(obj.source, obj.flags);
    copy.lastIndex = obj.lastIndex;
    hash.set(obj, copy);
    return copy;
  }

  // Map
  if (obj instanceof Map) {
    const copy = new Map();
    hash.set(obj, copy);
    obj.forEach((value, key) => {
      copy.set(deepClone(key, hash), deepClone(value, hash));
    });
    return copy;
  }

  // Set
  if (obj instanceof Set) {
    const copy = new Set();
    hash.set(obj, copy);
    obj.forEach(value => {
      copy.add(deepClone(value, hash));
    });
    return copy;
  }

  // Buffer/ArrayBuffer/TypedArray
  if (ArrayBuffer.isView(obj)) {
    const copy = new obj.constructor(obj.buffer.slice(0));
    hash.set(obj, copy);
    return copy;
  }

  if (obj instanceof ArrayBuffer) {
    const copy = obj.slice(0);
    hash.set(obj, copy);
    return copy;
  }

  // Array
  if (Array.isArray(obj)) {
    const copy = [];
    hash.set(obj, copy);
    obj.forEach((item, index) => {
      copy[index] = deepClone(item, hash);
    });
    return copy;
  }

  // Function - 引用复制（或可以返回新函数）
  if (typeof obj === 'function') {
    return obj;
  }

  // 普通对象
  const copy = Object.create(Object.getPrototypeOf(obj));
  hash.set(obj, copy);

  // 处理所有属性（包括Symbol和不可枚举）
  const allKeys = Reflect.ownKeys(obj);
  for (const key of allKeys) {
    const descriptor = Object.getOwnPropertyDescriptor(obj, key);
    if (descriptor.value) {
      descriptor.value = deepClone(descriptor.value, hash);
    }
    Object.defineProperty(copy, key, descriptor);
  }

  return copy;
}

