questions.reference_solution:
function throttle(fn, delay) {
  let timer = null;
  let lastArgs = null;
  let lastThis = null;
  let lastCallTime = 0;
  function invoke() {
    fn.apply(lastThis, lastArgs);
    lastCallTime = Date.now();
    timer = null;
    lastArgs = null;
    lastThis = null;
  }
  function throttled(...args) {
    lastArgs = args;
    lastThis = this;
    const now = Date.now();
    const remaining = delay - (now - lastCallTime);
    if (remaining <= 0) {
      if (timer) {
        clearTimeout(timer);
        timer = null;
      }
      invoke();
    } else if (!timer) {
      timer = setTimeout(() => {
        invoke();
      }, remaining);
    }
  }
  throttled.cancel = function() {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = null;
    lastThis = null;
  };
  throttled.flush = function() {
    if (timer || lastArgs) {
      if (timer) {
        clearTimeout(timer);
        timer = null;
      }
      invoke();
    }
  };
  throttled.pending = function() {
    return timer !== null;
  };
  return throttled;
}
function debounce(fn, delay) {
  let timer = null;
  let lastArgs = null;
  let lastThis = null;
  function invoke() {
    fn.apply(lastThis, lastArgs);
    timer = null;
    lastArgs = null;
    lastThis = null;
  }
  function debounced(...args) {
    lastArgs = args;
    lastThis = this;
    if (timer) {
      clearTimeout(timer);
    }
    timer = setTimeout(invoke, delay);
  }
  debounced.cancel = function() {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = null;
    lastThis = null;
  };
  debounced.flush = function() {
    if (timer) {
      clearTimeout(timer);
      invoke();
    }
  };
  debounced.pending = function() {
    return timer !== null;
  };
  return debounced;
}

