class EventEmitter {
  constructor() {
    this._events = Object.create(null);
    this._maxListeners = EventEmitter.defaultMaxListeners;
  }
  static defaultMaxListeners = 10;
  on(event, listener) {
    if (typeof listener !== 'function') {
      throw new TypeError('listener must be a function');
    }
    if (!this._events[event]) {
      this._events[event] = [];
    }
    if (this._events[event].length >= this._maxListeners) {
      console.warn(`Possible EventEmitter memory leak: ${event}`);
    }
    this._events[event].push(listener);
    return this;
  }
  prependListener(event, listener) {
    if (typeof listener !== 'function') {
      throw new TypeError('listener must be a function');
    }
    if (!this._events[event]) {
      this._events[event] = [];
    }
    this._events[event].unshift(listener);
    return this;
  }
  once(event, listener) {
    if (typeof listener !== 'function') {
      throw new TypeError('listener must be a function');
    }
    const onceWrapper = (...args) => {
      this.off(event, onceWrapper);
      listener.apply(this, args);
    };
    onceWrapper._original = listener;
    return this.on(event, onceWrapper);
  }
  off(event, listener) {
    if (!this._events[event]) return this;

    if (!listener) {
      delete this._events[event];
      return this;
    }
    const listeners = this._events[event];
    for (let i = listeners.length - 1; i >= 0; i--) {
      if (listeners[i] === listener || listeners[i]._original === listener) {
        listeners.splice(i, 1);
        break;
      }
    }
    if (listeners.length === 0) {
      delete this._events[event];
    }
    return this;
  }
  emit(event, ...args) {
    if (!this._events[event]) return false;

    const listeners = this._events[event].slice();
    let hasError = false;

    for (const listener of listeners) {
      try {
        listener.apply(this, args);
      } catch (error) {
        hasError = true;
        if (this._events['error'] && event !== 'error') {
          this.emit('error', error);
        } else {
          console.error('Unhandled error in listener:', error);
        }
      }
    }
    return !hasError;
  }
  removeAllListeners(event) {
    if (event) {
      delete this._events[event];
    } else {
      this._events = Object.create(null);
    }
    return this;
  }
  listenerCount(event) {
    return this._events[event] ? this._events[event].length : 0;
  }
  setMaxListeners(n) {
    this._maxListeners = n;
    return this;
  }
  getMaxListeners() {
    return this._maxListeners;
  }
}

