function concurrencyLimit(tasks, limit) {
  return new Promise((resolve, reject) => {
    const results = [];
    const errors = [];
    let completed = 0;
    let currentIndex = 0;
    let aborted = false;
    const abortController = {
      aborted: false,
      abort() {
        this.aborted = true;
        aborted = true;
      }
    };
    function runNext() {
      if (aborted || currentIndex >= tasks.length) {
        if (completed === tasks.length || aborted) {
          resolve({ results, errors, aborted });
        }
        return;
      }
      const index = currentIndex++;
      const task = tasks[index];
      Promise.resolve()
        .then(() => task())
        .then(result => {
          results[index] = result;
        })
        .catch(error => {
          errors[index] = error;
        })
        .finally(() => {
          completed++;
          runNext();
        });
    }
    // 启动初始任务
    const initialCount = Math.min(limit, tasks.length);
    for (let i = 0; i < initialCount; i++) {
      runNext();
    }
    // 返回带abort的promise
    return Object.assign(
      new Promise((res) => {
        const originalResolve = resolve;
        resolve = (value) => {
          res(value);
        };
      }),
      { abort: () => abortController.abort() }
    );
  });
}

