// 1. TupleToUnion
type TupleToUnion<T extends any[]> = T extends (infer U)[] ? U : never;
// 或更简单
type TupleToUnion<T extends any[]> = T[number];
// 2. UnionToTuple（简化版，完整实现需要更复杂的技巧）
type UnionToTuple<U, Last = LastOfUnion<U>> = 
  [U] extends [never] ? [] : 
  [...UnionToTuple<Exclude<U, Last>>, Last];
type LastOfUnion<U> = 
  UnionToIntersection<U extends any ? () => U : never> extends () => infer R ? R : never;
// 3. UnionToIntersection
type UnionToIntersection<U> = 
  (U extends any ? (k: U) => void : never) extends (k: infer I) => void ? I : never;
// 4. GetRequired
type GetRequired<T> = {
  [K in keyof T as {} extends Pick<T, K> ? never : K]: T[K]
}[keyof T];
// 或使用另一种方式
type GetRequiredKeys<T> = keyof {
  [K in keyof T as T extends { [_ in K]: T[K] } ? K : never]: T[K]
};
// 5. GetOptional
type GetOptional<T> = {
  [K in keyof T as {} extends Pick<T, K> ? K : never]: T[K]
}[keyof T];

