const state = reactive({ count: 0, nested: { value: 1 } });
effect(() => {
  console.log('count:', state.count);
}); // 立即输出: count: 0
state.count++; // 输出: count: 1
const double = computed(() => state.count * 2);
console.log(double.value); // 2

